mapper.update:
update t_r_mcp_token
set status = 'REVOKED',
    revoked_at = #{revokedAt},
    revoked_reason = #{revokedReason}
where id = #{id}
  and status = 'ACTIVE'

update t_r_mcp_token
set last_used_at = #{lastUsedAt},
    last_used_ip = #{lastUsedIp}
where id = #{id}

mapper.select:
select id
from t_r_mcp_token
where status = 'ACTIVE'
  and expires_at < #{now}
order by expires_at asc
limit #{limit}
